def gen(rng, size):
    colors = 'RYBGW'
    while True:
        bn = rng.randint(1, 7)
        board = []
        for _ in range(bn):
            c = rng.choice(colors)
            board.append(c)
        # ensure no initial run of 3+
        ok = True
        for i in range(len(board) - 2):
            if board[i] == board[i+1] == board[i+2]:
                ok = False
                break
        if ok:
            break
    hn = rng.randint(1, 4)
    hand = ''.join(rng.choice(colors) for _ in range(hn))
    return [''.join(board), hand]

