class Solution:
    def findMinStep(self, board, hand):
        from functools import lru_cache
        def collapse(s):
            i = 0
            while i < len(s):
                j = i
                while j < len(s) and s[j] == s[i]:
                    j += 1
                if j - i >= 3:
                    s = s[:i] + s[j:]
                    i = 0
                else:
                    i = j
            return s
        hand_key = ''.join(sorted(hand))
        @lru_cache(maxsize=None)
        def solve(b, h):
            if b == '':
                return 0
            if h == '':
                return -1
            best = -1
            for hi in range(len(h)):
                if hi > 0 and h[hi] == h[hi-1]:
                    continue
                ball = h[hi]
                rest = h[:hi] + h[hi+1:]
                for pos in range(len(b) + 1):
                    nb = collapse(b[:pos] + ball + b[pos:])
                    r = solve(nb, rest)
                    if r >= 0:
                        if best == -1 or r + 1 < best:
                            best = r + 1
            return best
        return solve(board, hand_key)

