class Solution:
    def findMinStep(self, board, hand):
        from collections import deque
        def collapse(s):
            i = 0
            while i < len(s):
                j = i
                while j < len(s) and s[j] == s[i]:
                    j += 1
                if j - i >= 3:
                    s = s[:i] + s[j:]
                    i = 0
                else:
                    i = j
            return s
        start_hand = ''.join(sorted(hand))
        start = (board, start_hand)
        seen = {start}
        dq = deque([(board, start_hand, 0)])
        while dq:
            b, h, steps = dq.popleft()
            if b == '':
                return steps
            for hi in range(len(h)):
                if hi > 0 and h[hi] == h[hi-1]:
                    continue
                ball = h[hi]
                rest = h[:hi] + h[hi+1:]
                for pos in range(len(b) + 1):
                    nb = collapse(b[:pos] + ball + b[pos:])
                    state = (nb, rest)
                    if state not in seen:
                        seen.add(state)
                        dq.append((nb, rest, steps + 1))
        return -1

