var findMinStep = function(board, hand) {
    const collapse = (s) => {
        let i = 0;
        while (i < s.length) {
            let j = i;
            while (j < s.length && s[j] === s[i]) j++;
            if (j - i >= 3) {
                s = s.slice(0, i) + s.slice(j);
                i = 0;
            } else {
                i = j;
            }
        }
        return s;
    };
    const startHand = hand.split('').sort().join('');
    const seen = new Set([board + '#' + startHand]);
    const dq = [[board, startHand, 0]];
    let head = 0;
    while (head < dq.length) {
        const [b, h, steps] = dq[head++];
        if (b === '') return steps;
        for (let hi = 0; hi < h.length; hi++) {
            if (hi > 0 && h[hi] === h[hi-1]) continue;
            const ball = h[hi];
            const rest = h.slice(0, hi) + h.slice(hi+1);
            for (let pos = 0; pos <= b.length; pos++) {
                const nb = collapse(b.slice(0, pos) + ball + b.slice(pos));
                const key = nb + '#' + rest;
                if (!seen.has(key)) {
                    seen.add(key);
                    dq.push([nb, rest, steps + 1]);
                }
            }
        }
    }
    return -1;
};
